"use client";

import { Icon } from "@/components/shared/icon";
import type { WorkflowLibraryGroup, WorkflowStudioData } from "@/lib/types";
import { cx } from "@/lib/utils";

type WorkflowNodeLibraryProps = {
  templates: WorkflowStudioData["templates"];
  nodeLibrary: WorkflowStudioData["nodeLibrary"];
  selectedTemplateId: string;
  collapsed: boolean;
  onTemplateChange: (templateId: string) => void;
  onToggleCollapse: () => void;
};

const groupLabels: Record<WorkflowLibraryGroup, string> = {
  trigger: "触发器",
  input: "输入",
  ai: "AI 节点",
  logic: "逻辑控制",
  human: "人工协作",
  output: "输出",
};

const groupDescriptions: Record<WorkflowLibraryGroup, string> = {
  trigger: "接收任务、Webhook 或表单输入。",
  input: "上传文件、表单和上下文注入。",
  ai: "Dify Agent、知识库与模型工具。",
  logic: "条件分支、规则集与路径控制。",
  human: "审批、复核和人工兜底确认。",
  output: "通知、签署和归档等外部动作。",
};

export function WorkflowNodeLibrary({
  templates,
  nodeLibrary,
  selectedTemplateId,
  collapsed,
  onTemplateChange,
  onToggleCollapse,
}: WorkflowNodeLibraryProps) {
  const groupedNodes = Object.entries(groupLabels).map(([group, label]) => ({
    group: group as WorkflowLibraryGroup,
    label,
    description: groupDescriptions[group as WorkflowLibraryGroup],
    items: nodeLibrary.filter((item) => item.group === group),
  }));

  if (collapsed) {
    return (
      <aside className="flex min-h-[820px] flex-col border-r p-3" style={{ borderColor: "var(--border)" }}>
        <button
          type="button"
          onClick={onToggleCollapse}
          className="button-secondary flex h-11 w-11 items-center justify-center self-center rounded-2xl"
          aria-label="展开模板栏"
          title="展开模板栏"
        >
          <Icon name="chevronRight" className="h-4 w-4" />
        </button>

        <div className="mt-4 flex flex-1 flex-col items-center gap-3">
          {templates.map((template, index) => {
            const active = template.id === selectedTemplateId;

            return (
              <button
                key={template.id}
                type="button"
                onClick={() => onTemplateChange(template.id)}
                title={template.title}
                className={cx(
                  "flex h-12 w-12 items-center justify-center rounded-2xl border text-xs font-semibold transition",
                  active
                    ? "border-cyan-400/20 bg-cyan-400/10 text-cyan-100"
                    : "border-white/8 bg-white/4 text-secondary hover:border-cyan-400/14 hover:bg-cyan-400/6",
                )}
              >
                {String(index + 1).padStart(2, "0")}
              </button>
            );
          })}
        </div>

        <div className="surface-card rounded-[24px] px-2 py-3 text-center">
          <p className="text-[10px] font-semibold uppercase tracking-[0.16em] text-tertiary">
            {nodeLibrary.length} 节点
          </p>
        </div>
      </aside>
    );
  }

  return (
    <aside className="flex min-h-[820px] flex-col border-r" style={{ borderColor: "var(--border)" }}>
      <div className="border-b p-4" style={{ borderColor: "var(--border)" }}>
        <div className="flex items-center justify-between gap-3">
          <div>
            <p className="text-[11px] font-semibold uppercase tracking-[0.22em] text-tertiary">
              Workflow Library
            </p>
            <h3 className="mt-2 text-base font-semibold text-primary">场景模板</h3>
          </div>

          <div className="flex items-center gap-2">
            <button type="button" className="button-secondary rounded-2xl px-3 py-2 text-xs font-semibold">
              导入 JSON
            </button>
            <button
              type="button"
              onClick={onToggleCollapse}
              className="button-secondary flex h-10 w-10 items-center justify-center rounded-2xl"
              aria-label="收起模板栏"
              title="收起模板栏"
            >
              <Icon name="chevronLeft" className="h-4 w-4" />
            </button>
          </div>
        </div>

        <div className="mt-4 space-y-3">
          {templates.map((template) => {
            const active = template.id === selectedTemplateId;

            return (
              <button
                key={template.id}
                type="button"
                onClick={() => onTemplateChange(template.id)}
                className={cx(
                  "w-full rounded-[24px] border px-4 py-4 text-left transition",
                  active
                    ? "border-cyan-400/20 bg-cyan-400/10 shadow-[0_16px_40px_rgba(15,118,110,0.12)]"
                    : "border-white/8 bg-white/4 hover:border-cyan-400/14 hover:bg-cyan-400/6",
                )}
              >
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <p className="text-sm font-semibold text-primary">{template.title}</p>
                    <p className="mt-2 text-sm leading-6 text-secondary">{template.summary}</p>
                  </div>
                  <span className="chip-accent rounded-full px-2.5 py-1 text-[10px] font-semibold uppercase tracking-[0.18em]">
                    {template.category}
                  </span>
                </div>

                <div className="mt-4 flex flex-wrap gap-2">
                  {template.tags.map((tag) => (
                    <span key={tag} className="chip rounded-full px-2.5 py-1 text-[10px] font-semibold">
                      {tag}
                    </span>
                  ))}
                </div>

                <div className="mt-4 flex items-center justify-between text-xs text-secondary">
                  <span>{template.nodeCount} 个节点</span>
                  <span>更新于 {template.lastUpdated}</span>
                </div>
              </button>
            );
          })}
        </div>
      </div>

      <div className="scrollbar-thin flex-1 space-y-5 overflow-y-auto p-4">
        <div className="surface-card rounded-[24px] p-4">
          <div className="flex items-center gap-3">
            <div className="surface-accent flex h-11 w-11 items-center justify-center rounded-2xl">
              <Icon name="workflow" className="h-5 w-5 text-[var(--accent-strong)]" />
            </div>
            <div>
              <p className="text-sm font-semibold text-primary">节点库</p>
              <p className="mt-1 text-xs leading-5 text-secondary">
                当前先做可演示的固定模板，后续再接真实拖拽与保存接口。
              </p>
            </div>
          </div>
        </div>

        {groupedNodes.map((group) => (
          <section key={group.group} className="space-y-3">
            <div>
              <p className="text-[11px] font-semibold uppercase tracking-[0.2em] text-tertiary">
                {group.label}
              </p>
              <p className="mt-1 text-xs leading-5 text-secondary">{group.description}</p>
            </div>

            <div className="space-y-2">
              {group.items.map((item) => (
                <div
                  key={item.id}
                  className="surface-card rounded-[22px] px-3.5 py-3 transition hover:border-cyan-400/16 hover:bg-cyan-400/6"
                >
                  <div className="flex items-start gap-3">
                    <div className="surface-card-strong flex h-10 w-10 shrink-0 items-center justify-center rounded-2xl">
                      <Icon name={item.icon} className="h-4 w-4 text-primary" />
                    </div>
                    <div className="min-w-0">
                      <div className="flex items-center justify-between gap-2">
                        <p className="text-sm font-semibold text-primary">{item.label}</p>
                        <span className="chip rounded-full px-2 py-0.5 text-[10px] font-semibold uppercase tracking-[0.16em]">
                          {item.type}
                        </span>
                      </div>
                      <p className="mt-1 text-xs leading-5 text-secondary">{item.description}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </section>
        ))}
      </div>
    </aside>
  );
}
