"use client";

import { Icon } from "@/components/shared/icon";
import { StatusBadge } from "@/components/shared/status-badge";
import type { WorkflowNodeCard, WorkflowSnapshot, WorkflowTemplateScenario } from "@/lib/types";
import { cx } from "@/lib/utils";

type WorkflowInspectorProps = {
  template: WorkflowTemplateScenario;
  selectedNode: WorkflowNodeCard | undefined;
  snapshot: WorkflowSnapshot;
  integrationPoints: string[];
  onShowExecutions: () => void;
};

const visualStateLabels: Record<WorkflowNodeCard["state"], string> = {
  idle: "待配置",
  active: "当前主节点",
  success: "链路可用",
  warning: "需关注",
  error: "异常节点",
};

const visualStateClasses: Record<WorkflowNodeCard["state"], string> = {
  idle: "chip",
  active: "chip-accent",
  success: "border-emerald-400/20 bg-emerald-400/10 text-emerald-200",
  warning: "border-amber-400/20 bg-amber-400/10 text-amber-200",
  error: "border-rose-400/20 bg-rose-400/10 text-rose-200",
};

export function WorkflowInspector({
  template,
  selectedNode,
  snapshot,
  integrationPoints,
  onShowExecutions,
}: WorkflowInspectorProps) {
  const latestRun = snapshot.recentRuns[0];

  return (
    <aside className="scrollbar-thin min-h-[820px] overflow-y-auto p-4">
      <div className="space-y-4">
        <section className="surface-card rounded-[28px] p-4">
          <p className="text-[11px] font-semibold uppercase tracking-[0.2em] text-tertiary">
            Inspector
          </p>

          {selectedNode ? (
            <>
              <div className="mt-4 flex items-start gap-3">
                <div className="surface-card-strong flex h-12 w-12 items-center justify-center rounded-2xl">
                  <Icon name={selectedNode.icon} className="h-5 w-5 text-primary" />
                </div>
                <div className="min-w-0">
                  <div className="flex flex-wrap items-center gap-2">
                    <h3 className="text-base font-semibold text-primary">{selectedNode.title}</h3>
                    <span
                      className={cx(
                        "rounded-full border px-2.5 py-1 text-[10px] font-semibold uppercase tracking-[0.16em]",
                        visualStateClasses[selectedNode.state],
                      )}
                    >
                      {visualStateLabels[selectedNode.state]}
                    </span>
                  </div>
                  <p className="mt-2 text-sm leading-6 text-secondary">{selectedNode.subtitle}</p>
                </div>
              </div>

              {selectedNode.badges?.length ? (
                <div className="mt-4 flex flex-wrap gap-2">
                  {selectedNode.badges.map((badge) => (
                    <span key={badge} className="chip rounded-full px-2.5 py-1 text-[10px] font-semibold">
                      {badge}
                    </span>
                  ))}
                </div>
              ) : null}

              <div className="mt-5 space-y-3">
                {selectedNode.fields.map((field) => (
                  <div key={field.label} className="surface-card-strong rounded-[20px] px-3.5 py-3">
                    <p className="text-[11px] font-semibold uppercase tracking-[0.16em] text-tertiary">
                      {field.label}
                    </p>
                    <p className="mt-2 text-sm leading-6 text-primary">{field.value}</p>
                  </div>
                ))}
              </div>

              {selectedNode.notes?.length ? (
                <div className="mt-5">
                  <p className="text-[11px] font-semibold uppercase tracking-[0.16em] text-tertiary">
                    协作说明
                  </p>
                  <div className="mt-3 space-y-2">
                    {selectedNode.notes.map((note) => (
                      <div key={note} className="surface-card-strong rounded-[20px] px-3.5 py-3 text-sm leading-6 text-secondary">
                        {note}
                      </div>
                    ))}
                  </div>
                </div>
              ) : null}
            </>
          ) : (
            <div className="mt-4 rounded-[22px] border border-dashed px-4 py-5 text-sm leading-6 text-secondary" style={{ borderColor: "var(--border-strong)" }}>
              当前没有选中节点，点击画布中的任意节点查看配置摘要。
            </div>
          )}
        </section>

        <section className="surface-card rounded-[28px] p-4">
          <div className="flex items-center justify-between gap-3">
            <div>
              <p className="text-[11px] font-semibold uppercase tracking-[0.2em] text-tertiary">
                Template Summary
              </p>
              <h3 className="mt-2 text-base font-semibold text-primary">{template.title}</h3>
            </div>
            <StatusBadge status={snapshot.status} />
          </div>

          <p className="mt-3 text-sm leading-6 text-secondary">{template.summary}</p>

          <div className="mt-4 grid grid-cols-2 gap-3">
            <div className="surface-card-strong rounded-[20px] p-3">
              <p className="text-[11px] uppercase tracking-[0.16em] text-tertiary">节点数</p>
              <p className="mt-2 text-lg font-semibold text-primary">{template.nodeCount}</p>
            </div>
            <div className="surface-card-strong rounded-[20px] p-3">
              <p className="text-[11px] uppercase tracking-[0.16em] text-tertiary">集成数</p>
              <p className="mt-2 text-lg font-semibold text-primary">{template.integrations.length}</p>
            </div>
          </div>

          <div className="mt-4 flex flex-wrap gap-2">
            {template.integrations.map((integration) => (
              <span key={integration} className="chip-accent rounded-full px-2.5 py-1 text-[10px] font-semibold">
                {integration}
              </span>
            ))}
          </div>
        </section>

        <section className="surface-card rounded-[28px] p-4">
          <div className="flex items-center justify-between gap-3">
            <div>
              <p className="text-[11px] font-semibold uppercase tracking-[0.2em] text-tertiary">
                Execution Snapshot
              </p>
              <h3 className="mt-2 text-base font-semibold text-primary">{snapshot.title}</h3>
            </div>
            <button type="button" onClick={onShowExecutions} className="button-secondary rounded-2xl px-3 py-2 text-xs font-semibold">
              查看执行
            </button>
          </div>

          <p className="mt-3 text-sm leading-6 text-secondary">{snapshot.notice}</p>

          {latestRun ? (
            <div className="mt-4 rounded-[22px] border px-4 py-4" style={{ borderColor: "var(--border)" }}>
              <div className="flex items-center justify-between gap-3">
                <p className="text-sm font-semibold text-primary">{latestRun.summary}</p>
                <StatusBadge status={latestRun.status} />
              </div>
              <div className="mt-3 grid gap-2 text-xs text-secondary">
                <p>触发来源: {latestRun.trigger}</p>
                <p>开始时间: {latestRun.startedAt}</p>
                <p>耗时: {latestRun.duration}</p>
              </div>
            </div>
          ) : (
            <div className="mt-4 rounded-[22px] border border-dashed px-4 py-4 text-sm leading-6 text-secondary" style={{ borderColor: "var(--border-strong)" }}>
              当前还没有执行记录，可直接切换到执行标签查看空状态。
            </div>
          )}
        </section>

        <section className="surface-card rounded-[28px] p-4">
          <p className="text-[11px] font-semibold uppercase tracking-[0.2em] text-tertiary">
            Backend Slots
          </p>
          <div className="mt-4 space-y-2">
            {integrationPoints.map((point) => (
              <div key={point} className="surface-card-strong rounded-[18px] px-3 py-2.5 font-mono text-[12px] text-secondary">
                {point}
              </div>
            ))}
          </div>
        </section>
      </div>
    </aside>
  );
}
