"use client";

import { useState } from "react";
import { Icon } from "@/components/shared/icon";
import { StatusBadge } from "@/components/shared/status-badge";
import { WorkflowCanvas } from "@/components/workflows/workflow-canvas";
import { WorkflowExecutionsPanel } from "@/components/workflows/workflow-executions-panel";
import { WorkflowInspector } from "@/components/workflows/workflow-inspector";
import { WorkflowNodeLibrary } from "@/components/workflows/workflow-node-library";
import type { TaskCenterViewState, WorkflowStudioData, WorkflowTab } from "@/lib/types";
import { cx } from "@/lib/utils";

type WorkflowStudioPageProps = {
  data: WorkflowStudioData;
};

const tabOptions: Array<{ id: WorkflowTab; label: string }> = [
  { id: "editor", label: "Editor" },
  { id: "executions", label: "Executions" },
];

const viewStateOptions: Array<{ id: TaskCenterViewState; label: string }> = [
  { id: "default", label: "Default" },
  { id: "loading", label: "Loading" },
  { id: "success", label: "Success" },
  { id: "empty", label: "Empty" },
  { id: "error", label: "Error" },
];

export function WorkflowStudioPage({ data }: WorkflowStudioPageProps) {
  const [selectedTemplateId, setSelectedTemplateId] = useState(data.defaultTemplateId);
  const selectedTemplate =
    data.templates.find((template) => template.id === selectedTemplateId) ?? data.templates[0];
  const [selectedNodeId, setSelectedNodeId] = useState(selectedTemplate.defaultSelectedNodeId);
  const [activeTab, setActiveTab] = useState<WorkflowTab>("editor");
  const [viewState, setViewState] = useState<TaskCenterViewState>("success");
  const [isActive, setIsActive] = useState(true);
  const [libraryCollapsed, setLibraryCollapsed] = useState(true);

  const snapshot = data.stateSnapshots[viewState];
  const selectedNode =
    selectedTemplate.nodes.find((node) => node.id === selectedNodeId) ??
    selectedTemplate.nodes.find((node) => node.id === selectedTemplate.defaultSelectedNodeId) ??
    selectedTemplate.nodes[0];
  const manualNodeCount = selectedTemplate.nodes.filter(
    (node) => node.type === "approval" || node.type === "sign",
  ).length;

  function handleTemplateChange(templateId: string) {
    const nextTemplate = data.templates.find((template) => template.id === templateId);

    setSelectedTemplateId(templateId);
    setSelectedNodeId(nextTemplate?.defaultSelectedNodeId ?? selectedTemplate.defaultSelectedNodeId);
    setActiveTab("editor");
  }

  function handleInspectNode(nodeId: string) {
    setSelectedNodeId(nodeId);
    setActiveTab("editor");
  }

  return (
    <div className="space-y-6">
      <section className="panel-highlight rounded-[32px] p-6 sm:p-8">
        <div className="grid gap-6 xl:grid-cols-[1.08fr_0.92fr]">
          <div>
            <p className="eyebrow text-xs font-semibold uppercase tracking-[0.28em]">
              Workflow Orchestration
            </p>
            <div className="mt-4 flex flex-wrap items-center gap-3">
              <h1 className="text-3xl font-semibold tracking-tight text-primary sm:text-4xl">
                {data.workflowName}
              </h1>
              <StatusBadge status={snapshot.status} />
            </div>
            <p className="mt-4 max-w-3xl text-base leading-7 text-secondary">
              {data.workflowSubtitle}
            </p>

            <div className="mt-5 flex flex-wrap gap-2">
              <span className="chip-accent rounded-full px-3 py-1.5 text-[11px] font-semibold uppercase tracking-[0.16em]">
                {selectedTemplate.category}
              </span>
              {selectedTemplate.tags.map((tag) => (
                <span key={tag} className="chip rounded-full px-3 py-1.5 text-[11px] font-semibold">
                  {tag}
                </span>
              ))}
            </div>
          </div>

          <div className="grid gap-3 sm:grid-cols-2">
            <div className="surface-card rounded-[26px] p-4">
              <p className="text-xs uppercase tracking-[0.18em] text-tertiary">当前模板</p>
              <p className="mt-3 text-lg font-semibold text-primary">{selectedTemplate.title}</p>
            </div>
            <div className="surface-card rounded-[26px] p-4">
              <p className="text-xs uppercase tracking-[0.18em] text-tertiary">集成位</p>
              <p className="mt-3 text-lg font-semibold text-primary">
                {selectedTemplate.integrations.length} 个
              </p>
            </div>
            <div className="surface-card rounded-[26px] p-4">
              <p className="text-xs uppercase tracking-[0.18em] text-tertiary">协作节点</p>
              <p className="mt-3 text-lg font-semibold text-primary">{manualNodeCount} 个人工兜底</p>
            </div>
            <div className="surface-card rounded-[26px] p-4">
              <p className="text-xs uppercase tracking-[0.18em] text-tertiary">最近保存</p>
              <p className="mt-3 text-lg font-semibold text-primary">{snapshot.savedAt}</p>
            </div>
          </div>
        </div>
      </section>

      <section className="panel overflow-hidden rounded-[34px]">
        <div className="border-b px-4 py-4 sm:px-5" style={{ borderColor: "var(--border)" }}>
          <div className="flex flex-col gap-4 xl:flex-row xl:items-center xl:justify-between">
            <div className="flex items-start gap-3">
              <div className="surface-card-strong flex h-12 w-12 items-center justify-center rounded-2xl">
                <Icon name="workflow" className="h-5 w-5 text-primary" />
              </div>
              <div>
                <div className="flex flex-wrap items-center gap-2">
                  <h2 className="text-lg font-semibold text-primary">{selectedTemplate.title}</h2>
                  <span className="chip rounded-full px-2.5 py-1 text-[10px] font-semibold uppercase tracking-[0.16em]">
                    {selectedTemplate.nodeCount} nodes
                  </span>
                </div>
                <p className="mt-2 text-sm leading-6 text-secondary">{selectedTemplate.summary}</p>
              </div>
            </div>

            <div className="flex flex-wrap items-center gap-3">
              <div className="surface-card-strong inline-flex rounded-2xl p-1">
                {tabOptions.map((tab) => (
                  <button
                    key={tab.id}
                    type="button"
                    onClick={() => setActiveTab(tab.id)}
                    className={cx(
                      "rounded-xl px-4 py-2 text-sm font-semibold transition",
                      activeTab === tab.id
                        ? "bg-[var(--surface-strong)] text-primary shadow-[0_10px_24px_rgba(15,23,42,0.1)]"
                        : "text-secondary",
                    )}
                  >
                    {tab.label}
                  </button>
                ))}
              </div>

              <div className="flex items-center gap-2 rounded-full border px-3 py-2" style={{ borderColor: "var(--border)" }}>
                <span className="text-xs font-semibold text-secondary">
                  {isActive ? "Active" : "Inactive"}
                </span>
                <button
                  type="button"
                  aria-pressed={isActive}
                  onClick={() => setIsActive((current) => !current)}
                  className={cx(
                    "relative h-7 w-12 rounded-full transition",
                    isActive ? "bg-cyan-400/18" : "bg-white/6",
                  )}
                >
                  <span
                    className={cx(
                      "absolute top-1 h-5 w-5 rounded-full bg-white transition",
                      isActive ? "left-6" : "left-1",
                    )}
                  />
                </button>
              </div>

              <button type="button" className="button-secondary rounded-2xl px-4 py-2.5 text-sm font-semibold">
                保存
              </button>
              <button type="button" className="button-secondary rounded-2xl px-4 py-2.5 text-sm font-semibold">
                运行
              </button>
              <button type="button" className="button-primary rounded-2xl px-4 py-2.5 text-sm font-semibold">
                发布
              </button>
            </div>
          </div>

          <div className="mt-4 flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
            <div className="flex flex-wrap gap-2">
              {viewStateOptions.map((option) => (
                <button
                  key={option.id}
                  type="button"
                  onClick={() => setViewState(option.id)}
                  className={cx(
                    "rounded-full border px-3 py-1.5 text-[11px] font-semibold uppercase tracking-[0.16em] transition",
                    viewState === option.id
                      ? "border-cyan-400/20 bg-cyan-400/10 text-cyan-100"
                      : "border-white/8 bg-white/4 text-slate-300 hover:border-cyan-400/12 hover:bg-cyan-400/6",
                  )}
                >
                  {option.label}
                </button>
              ))}
            </div>

            <div className="surface-card-strong flex items-center gap-3 rounded-2xl px-4 py-3 text-sm text-secondary">
              <span className="font-semibold text-primary">{snapshot.title}</span>
              <span className="hidden h-1 w-1 rounded-full bg-[var(--border-strong)] sm:block" />
              <span className="hidden sm:block">{snapshot.notice}</span>
            </div>
          </div>
        </div>

        {activeTab === "editor" ? (
          <div
            className={cx(
              "grid min-h-[820px] gap-0",
              libraryCollapsed
                ? "xl:grid-cols-[88px_minmax(720px,1fr)_296px]"
                : "xl:grid-cols-[276px_minmax(720px,1fr)_296px]",
            )}
          >
            <WorkflowNodeLibrary
              templates={data.templates}
              nodeLibrary={data.nodeLibrary}
              selectedTemplateId={selectedTemplate.id}
              collapsed={libraryCollapsed}
              onTemplateChange={handleTemplateChange}
              onToggleCollapse={() => setLibraryCollapsed((current) => !current)}
            />
            <div className="min-w-0 border-x" style={{ borderColor: "var(--border)" }}>
              <WorkflowCanvas
                template={selectedTemplate}
                snapshot={snapshot}
                selectedNodeId={selectedNode.id}
                onNodeSelect={setSelectedNodeId}
              />
            </div>
            <WorkflowInspector
              template={selectedTemplate}
              selectedNode={selectedNode}
              snapshot={snapshot}
              integrationPoints={data.integrationPoints}
              onShowExecutions={() => setActiveTab("executions")}
            />
          </div>
        ) : (
          <WorkflowExecutionsPanel
            template={selectedTemplate}
            snapshot={snapshot}
            integrationPoints={data.integrationPoints}
            onInspectNode={handleInspectNode}
            onShowEditor={() => setActiveTab("editor")}
          />
        )}
      </section>
    </div>
  );
}
