"use client";

import {
  Background,
  BackgroundVariant,
  Controls,
  MarkerType,
  ReactFlow,
  ReactFlowProvider,
  type Edge,
  type Node,
  type NodeTypes,
} from "@xyflow/react";
import { StatusBadge } from "@/components/shared/status-badge";
import {
  WorkflowFlowNode,
  type WorkflowFlowNodeType,
} from "@/components/workflows/workflow-flow-node";
import type { WorkflowSnapshot, WorkflowTemplateScenario } from "@/lib/types";

type WorkflowCanvasProps = {
  template: WorkflowTemplateScenario;
  snapshot: WorkflowSnapshot;
  selectedNodeId: string;
  onNodeSelect: (nodeId: string) => void;
};

type WorkflowFlowNodeData = WorkflowFlowNodeType["data"];

const nodeTypes: NodeTypes = {
  workflowNode: WorkflowFlowNode,
};

function getSourceHandleId(side: WorkflowTemplateScenario["edges"][number]["sourceSide"]) {
  if (side === "left") {
    return "left-source";
  }

  if (side === "top") {
    return "top-source";
  }

  return side;
}

function getTargetHandleId(side: WorkflowTemplateScenario["edges"][number]["targetSide"]) {
  if (side === "right") {
    return "right-target";
  }

  if (side === "bottom") {
    return "bottom-target";
  }

  return side;
}

function WorkflowFlow({
  template,
  snapshot,
  selectedNodeId,
  onNodeSelect,
}: WorkflowCanvasProps) {
  const nodes: Array<Node<WorkflowFlowNodeData, "workflowNode">> = template.nodes.map((node) => ({
    id: node.id,
    type: "workflowNode",
    position: { x: node.x, y: node.y },
    data: {
      node,
      selected: node.id === selectedNodeId,
    },
    draggable: true,
    selectable: true,
    style: {
      width: node.width,
      height: node.height,
      background: "transparent",
      border: "none",
      padding: 0,
    },
  }));

  const edges: Edge[] = template.edges.map((edge) => {
    return {
      id: edge.id,
      source: edge.source,
      target: edge.target,
      sourceHandle: getSourceHandleId(edge.sourceSide),
      targetHandle: getTargetHandleId(edge.targetSide),
      type: "smoothstep",
      label: edge.label,
      markerEnd: {
        type: MarkerType.ArrowClosed,
        width: 18,
        height: 18,
        color: edge.style === "dashed" ? "var(--accent)" : "var(--foreground-soft)",
      },
      animated: edge.style === "dashed",
      style: {
        stroke: edge.style === "dashed" ? "var(--accent)" : "var(--foreground-soft)",
        strokeWidth: edge.style === "dashed" ? 2.2 : 2,
        strokeDasharray: edge.style === "dashed" ? "8 8" : undefined,
        opacity: edge.style === "dashed" ? 0.78 : 0.88,
      },
      labelStyle: {
        fill: "var(--foreground)",
        fontSize: 11,
        fontWeight: 700,
      },
      labelBgStyle: {
        fill: "var(--surface-accent)",
        stroke: "var(--accent-border)",
        strokeWidth: 1,
      },
      labelBgPadding: [8, 4],
      labelBgBorderRadius: 999,
    };
  });

  return (
    <div className="flex min-h-[820px] flex-col">
      <div
        className="flex flex-wrap items-center justify-between gap-3 border-b px-4 py-3"
        style={{ borderColor: "var(--border)" }}
      >
        <div>
          <p className="text-[11px] font-semibold uppercase tracking-[0.2em] text-tertiary">
            Workflow Canvas
          </p>
          <div className="mt-2 flex flex-wrap items-center gap-2">
            <StatusBadge status={snapshot.status} />
            <span className="chip rounded-full px-2.5 py-1 text-[10px] font-semibold uppercase tracking-[0.16em]">
              {template.nodeCount} nodes
            </span>
            <span className="chip rounded-full px-2.5 py-1 text-[10px] font-semibold uppercase tracking-[0.16em]">
              保存于 {snapshot.savedAt}
            </span>
          </div>
        </div>

        <div className="surface-card-strong rounded-2xl px-4 py-3 text-sm text-secondary">
          React Flow 开源画布已接入，后续可继续扩展拖拽、连线编辑和节点配置持久化。
        </div>
      </div>

      <div className="workflow-grid relative min-h-[744px] overflow-hidden">
        <div className="pointer-events-none absolute inset-x-0 top-0 z-10 flex justify-center p-4">
          <div className="surface-card-strong inline-flex items-center gap-3 rounded-full px-4 py-2 text-xs text-secondary">
            <span className="font-semibold text-primary">{snapshot.title}</span>
            <span className="h-1 w-1 rounded-full bg-[var(--border-strong)]" />
            {snapshot.summary}
          </div>
        </div>

        <ReactFlow
          nodes={nodes}
          edges={edges}
          nodeTypes={nodeTypes}
          onNodeClick={(_, node) => onNodeSelect(node.id)}
          fitView
          fitViewOptions={{ padding: 0.12 }}
          minZoom={0.55}
          maxZoom={1.5}
          nodesConnectable={false}
          elementsSelectable
          panOnDrag
          zoomOnScroll
          className="h-[744px] w-full"
          style={{ background: "transparent" }}
        >
          <Background
            id="workflow-bg"
            variant={BackgroundVariant.Dots}
            gap={24}
            size={1.5}
            color="color-mix(in srgb, var(--border-strong) 68%, transparent)"
          />
          <Controls
            position="bottom-left"
            showInteractive={false}
            className="!border !shadow-none"
          />
        </ReactFlow>

        <div className="pointer-events-none absolute bottom-4 right-4 z-10">
          <div className="surface-card-strong rounded-2xl px-4 py-3 text-xs text-secondary">
            单击节点可在右侧查看配置摘要
          </div>
        </div>
      </div>
    </div>
  );
}

export function WorkflowCanvas(props: WorkflowCanvasProps) {
  return (
    <ReactFlowProvider>
      <WorkflowFlow {...props} />
    </ReactFlowProvider>
  );
}
